398	// render renders the sites.
399	func (h *HugoSites) render(l logg.LevelLogger, config *BuildCfg) error {
400		l = l.WithField("step", "render")
401		start := time.Now()
402		defer func() {
403			loggers.TimeTrackf(l, start, h.buildCounters.loggFields(), "")
404		}()
405	
406		siteRenderContext := &siteRenderContext{cfg: config, infol: l, multihost: h.Configs.IsMultihost}
407	
408		renderErr := func(err error) error {
409			if err == nil {
410				return nil
411			}
412			// In Hugo 0.141.0 we replaced the special error handling for resources.GetRemote
413			// with the more general try.
414			if strings.Contains(err.Error(), "can't evaluate field Err in type") {
415				if strings.Contains(err.Error(), "resource.Resource") {
416					return fmt.Errorf("%s: Resource.Err was removed in Hugo v0.141.0 and replaced with a new try keyword, see https://gohugo.io/functions/go-template/try/", err)
417				} else if strings.Contains(err.Error(), "template.HTML") {
418					return fmt.Errorf("%s: the return type of transform.ToMath was changed in Hugo v0.141.0 and the error handling replaced with a new try keyword, see https://gohugo.io/functions/go-template/try/", err)
419				}
420			}
421			return err
422		}
423	
424		i := 0
425	
426		for s := range h.allSites(nil) {
427			if s.conf.Segments.Config.SegmentFilter.ShouldExcludeCoarse(segments.SegmentQuery{Site: s.siteVector}) {
428				l.Logf("skip site %s not matching segments set in --renderSegments", s.resolveDimensionNames())
429				continue
430			}
431			siteRenderContext.languageIdx = s.siteVector.Language()
432			h.currentSite = s
433			for siteOutIdx, renderFormat := range s.renderFormats {
434				if s.conf.Segments.Config.SegmentFilter.ShouldExcludeCoarse(segments.SegmentQuery{Output: renderFormat.Name, Site: s.siteVector}) {
435					l.Logf("skip output format %q for site %s not matching segments set in --renderSegments", renderFormat.Name, s.resolveDimensionNames())
436					continue
437				}
438	
439				if err := func() error {
440					rc := tpl.RenderingContext{Site: s, SiteOutIdx: siteOutIdx}
441					h.BuildState.StartStageRender(rc)
442					defer h.BuildState.StopStageRender(rc)
443	
444					siteRenderContext.outIdx = siteOutIdx
445					siteRenderContext.sitesOutIdx = i
446					i++
447	
448					select {
449					case <-h.Done():
450						return nil
451					default:
452						for s2 := range h.allSites(nil) {
453							if err := s2.preparePagesForRender(s == s2, siteRenderContext.sitesOutIdx); err != nil {
454								return err
455							}
456						}
457						if !config.SkipRender {
458							ll := l.WithField("substep", "pages").
459								WithField("site", s.language.Lang).
460								WithField("outputFormat", renderFormat.Name)
461	
462							start := time.Now()
463	
464							if config.PartialReRender {
465								if err := s.renderPages(siteRenderContext); err != nil {
466									return err
467								}
468							} else {
469								if err := s.render(siteRenderContext); err != nil {
470									return renderErr(err)
471								}
472							}
473							loggers.TimeTrackf(ll, start, nil, "")
474						}
475					}
476					return nil
477				}(); err != nil {
478					return err
479				}
480	
481			}
482	
483		}
484	
485		return nil
486	}
487	
488	func (h *HugoSites) renderDeferred(l logg.LevelLogger) error {
489		l = l.WithField("step", "render deferred")
490		start := time.Now()
491	
492		var deferredCount int
493	
494		for rc, de := range h.Deps.BuildState.DeferredExecutionsGroupedByRenderingContext {
495			if de.FilenamesWithPostPrefix.Len() == 0 {
496				continue
497			}
498	
499			deferredCount += de.FilenamesWithPostPrefix.Len()
500	
501			s := rc.Site.(*Site)
502			for _, s2 := range h.Sites {
503				if err := s2.preparePagesForRender(s == s2, rc.SiteOutIdx); err != nil {
504					return err
505				}
506			}
507			if err := s.executeDeferredTemplates(de); err != nil {
508				return herrors.ImproveRenderErr(err)
509			}
510		}
511	
512		loggers.TimeTrackf(l, start, logg.Fields{
513			logg.Field{Name: "count", Value: deferredCount},
514		}, "")
515	
516		return nil
517	}
518	
519	func (s *Site) executeDeferredTemplates(de *deps.DeferredExecutions) error {
520		handleFile := func(filename string) error {
521			content, err := afero.ReadFile(s.BaseFs.PublishFs, filename)
522			if err != nil {
523				return err
524			}
525	
526			k := 0
527			changed := false
528	
529			for {
530				if k >= len(content) {
531					break
532				}
533				l := bytes.Index(content[k:], []byte(tpl.HugoDeferredTemplatePrefix))
534				if l == -1 {
535					break
536				}
537				m := bytes.Index(content[k+l:], []byte(tpl.HugoDeferredTemplateSuffix)) + len(tpl.HugoDeferredTemplateSuffix)
538	
539				low, high := k+l, k+l+m
540	
541				forward := l + m
542				id := string(content[low:high])
543	
544				if err := func() error {
545					deferred, found := de.Executions.Get(id)
546					if !found {
547						panic(fmt.Sprintf("deferred execution with id %q not found", id))
548					}
549					deferred.Mu.Lock()
550					defer deferred.Mu.Unlock()
551	
552					if !deferred.Executed {
553						tmpl := s.Deps.GetTemplateStore()
554						ti := s.TemplateStore.LookupByPath(deferred.TemplatePath)
555						if ti == nil {
556							panic(fmt.Sprintf("template %q not found", deferred.TemplatePath))
557						}
558	
559						if err := func() error {
560							buf := bufferpool.GetBuffer()
561							defer bufferpool.PutBuffer(buf)
562	
563							err = tmpl.ExecuteWithContext(deferred.Ctx, ti, buf, deferred.Data)
564							if err != nil {
565								return err
566							}
567							deferred.Result = buf.String()
568							deferred.Executed = true
569	
570							return nil
571						}(); err != nil {
572							return err
573						}
574					}
575	
576					content = append(content[:low], append([]byte(deferred.Result), content[high:]...)...)
577					forward = len(deferred.Result)
578					changed = true
579	
580					return nil
581				}(); err != nil {
582					return err
583				}
584	
585				k += forward
586			}
587	
588			if changed {
589				return afero.WriteFile(s.BaseFs.PublishFs, filename, content, 0o666)
590			}
591	
592			return nil
593		}
594	
595		g := rungroup.Run(context.Background(), rungroup.Config[string]{
596			NumWorkers: s.h.numWorkers,
597			Handle: func(ctx context.Context, filename string) error {
598				return handleFile(filename)
599			},
600		})
601	
602		de.FilenamesWithPostPrefix.ForEeach(func(filename string, _ bool) bool {
603			g.Enqueue(filename)
604			return true
605		})
606	
607		return g.Wait()
608	}
