1282	func (s *Site) handleContentAdapterChanges(bi pagesfromdata.BuildInfo, buildConfig *BuildCfg) {
1283		if !s.h.isRebuild() {
1284			return
1285		}
1286	
1287		if len(bi.ChangedIdentities) > 0 {
1288			buildConfig.WhatChanged.Add(bi.ChangedIdentities...)
1289			buildConfig.WhatChanged.needsPagesAssembly = true
1290		}
1291	
1292		for _, p := range bi.DeletedPaths {
1293			pp := paths.AddLeadingSlash(path.Join(bi.Path.Base(), p.Path))
1294			df := func(n contentNode) bool {
1295				if len(p.Hashes) == 0 {
1296					return true
1297				}
1298				if nn, ok := n.(contentNodeSourceEntryIDProvider); ok {
1299					if i, ok := nn.nodeSourceEntryID().(uint64); ok && i != 0 {
1300						if _, found := p.Hashes[i]; found {
1301							return true
1302						}
1303					}
1304				}
1305				return false
1306			}
1307	
1308			if v, count := s.pageMap.treePages.DeleteFuncRaw(pp, df); count > 0 {
1309				buildConfig.WhatChanged.Add(cnh.GetIdentity(v))
1310			}
1311			if v, count := s.pageMap.treeResources.DeleteFuncRaw(pp, df); count > 0 {
1312				buildConfig.WhatChanged.Add(cnh.GetIdentity(v))
1313	
1314				// A deleted resource may affect its parent page.
1315				if _, v := s.pageMap.treePages.LongestPrefiValueRaw(pp); v != nil {
1316					buildConfig.WhatChanged.Add(cnh.GetIdentity(v))
1317				}
1318			}
1319		}
1320	}
